'use strict';
const GTM_ID = 'GTM-XXXXXXX';
const FB_PIXEL = 'XXXXXXXXXX';
function loadGTM() {
(function(w,d,s,l,i){
w[l]=w[l]||[];
w[l].push({'gtm.start':new Date().getTime(),event:'gtm.js'});
var f=d.getElementsByTagName(s)[0],
j=d.createElement(s),
dl=l!='dataLayer'?'&l='+l:'';
j.async=true;
j.src='https://www.googletagmanager.com/gtm.js?id='+i+dl;
f.parentNode.insertBefore(j,f);
})(window,document,'script','dataLayer',GTM_ID);
}
function loadFBPixel() {
!function(f,b,e,v,n,t,s){
if(f.fbq)return;
n=f.fbq=function(){n.callMethod?n.callMethod.apply(n,arguments):n.queue.push(arguments)};
if(!f._fbq)f._fbq=n;n.push=n;n.loaded=!0;n.version='2.0';
n.queue=[];t=b.createElement(e);t.async=!0;t.src=v;
s=b.getElementsByTagName(e)[0];s.parentNode.insertBefore(t,s)
}(window,document,'script','https://connect.facebook.net/en_US/fbevents.js');
fbq('init', FB_PIXEL);
fbq('track','PageView');
}
function pdpaGrant(accepted) {
const expires = new Date();
expires.setDate(expires.getDate() + 180);
localStorage.setItem('pdpa', accepted ? '1' : '0');
localStorage.setItem('pdpa_exp', expires.getTime());
document.getElementById('pdpa-banner').classList.remove('show');
if (accepted) {
gtag('consent','update',{
'analytics_storage': 'granted',
'ad_storage': 'granted',
'ad_user_data': 'granted',
'ad_personalization': 'granted'
});
loadGTM();
loadFBPixel();
}
}
(function initConsent() {
const val = localStorage.getItem('pdpa');
const exp = parseInt(localStorage.getItem('pdpa_exp') || '0');
const expired = Date.now() > exp;
if (val === null || expired) {
setTimeout(() => document.getElementById('pdpa-banner').classList.add('show'), 1500);
} else if (val === '1') {
gtag('consent','update',{
'analytics_storage':'granted','ad_storage':'granted',
'ad_user_data':'granted','ad_personalization':'granted'
});
loadGTM();
loadFBPixel();
}
})();
function trackClick(label) {
window.dataLayer = window.dataLayer || [];
window.dataLayer.push({
event: 'cta_click',
cta_label: label,
page_url: window.location.href
});
if (typeof gtag !== 'undefined') {
gtag('event','cta_click',{event_category:'CTA',event_label:label});
}
if (typeof fbq !== 'undefined') {
fbq('track','Lead',{content_name: label});
}
}
const io = new IntersectionObserver((entries) => {
entries.forEach(e => {
if (e.isIntersecting) { e.target.classList.add('in'); io.unobserve(e.target); }
});
}, {threshold: 0.08, rootMargin: '0px 0px -40px 0px'});
document.querySelectorAll('.reveal,.reveal-l,.reveal-r').forEach(el => io.observe(el));
const sticky = document.getElementById('sticky');
const backTop = document.getElementById('back-top');
window.addEventListener('scroll', () => {
const y = window.scrollY;
sticky.classList.toggle('show', y > 400);
backTop.classList.toggle('show', y > 400);
}, {passive: true});
(function startCountdown() {
const KEY = 'acp_cd_end';
let end = parseInt(sessionStorage.getItem(KEY) || '0');
if (!end || end < Date.now()) {
const h = 2 + Math.floor(Math.random() * 6);
const m = Math.floor(Math.random() * 60);
end = Date.now() + (h * 3600 + m * 60) * 1000;
sessionStorage.setItem(KEY, end);
}
function tick() {
const diff = Math.max(0, end - Date.now());
document.getElementById('cdH').textContent = String(Math.floor(diff/3600000)).padStart(2,'0');
document.getElementById('cdM').textContent = String(Math.floor((diff%3600000)/60000)).padStart(2,'0');
document.getElementById('cdS').textContent = String(Math.floor((diff%60000)/1000)).padStart(2,'0');
if (diff > 0) setTimeout(tick, 1000);
}
tick();
})();
function toggleFaq(btn) {
const item = btn.closest('.fitem');
const ans = item.querySelector('.fans');
const open = item.classList.contains('open');
document.querySelectorAll('.fitem.open').forEach(fi => {
fi.classList.remove('open');
fi.querySelector('.fans').style.height = '0';
});
if (!open) {
item.classList.add('open');
ans.style.height = ans.scrollHeight + 'px';
}
}
function submitHeroForm() {
const name = document.getElementById('hc-name').value.trim();
const tel = document.getElementById('hc-tel').value.trim();
const pdpa = document.getElementById('hc-pdpa') && document.getElementById('hc-pdpa').checked;
if (!name) { alert('กรุณากรอกชื่อครับ'); return; }
if (!tel || tel.replace(/\D/g,'').length < 9) { alert('กรุณากรอกเบอร์โทรศัพท์ที่ถูกต้องครับ'); return; }
if (!pdpa) { alert('กรุณายินยอมนโยบายความเป็นส่วนตัวก่อนดำเนินการต่อครับ'); return; }
document.getElementById('f-name').value = name;
document.getElementById('f-tel').value = tel;
document.getElementById('f-qty').value = document.getElementById('hc-qty').value;
trackClick('hero-card-submit');
showSuccess();
}
function submitMainForm() {
const name = document.getElementById('f-name').value.trim();
const tel = document.getElementById('f-tel').value.trim();
const pdpa = document.getElementById('f-pdpa') && document.getElementById('f-pdpa').checked;
const errEl = document.getElementById('form-err');
errEl.style.display = 'none';
if (!name || !tel) {
errEl.style.display = 'block';
errEl.textContent = 'กรุณากรอกชื่อและเบอร์โทรศัพท์ครับ';
return;
}
if (!pdpa) {
errEl.style.display = 'block';
errEl.textContent = 'กรุณายินยอมนโยบายความเป็นส่วนตัวเพื่อดำเนินการต่อ';
return;
}
trackClick('main-form-submit');
window.dataLayer = window.dataLayer || [];
window.dataLayer.push({
event: 'form_submit',
form_id: 'booking_main',
package: document.getElementById('f-package') ? document.getElementById('f-package').value : '',
units: document.getElementById('f-qty').value
});
if (typeof fbq !== 'undefined') { fbq('track','CompleteRegistration'); }
showSuccess();
}
function showSuccess() {
document.getElementById('form-fields').style.display = 'none';
document.getElementById('form-success').classList.add('show');
document.getElementById('booking-form').scrollIntoView({behavior:'smooth',block:'center'});
}
const proofs = [
{name:'สมหญิง', loc:'ลาดพร้าว', action:'เพิ่งจองคิวล้างแอร์', time:'2 นาทีที่แล้ว'},
{name:'วิชัย', loc:'พระโขนง', action:'จองแพ็ค Standard 4 เครื่อง', time:'5 นาทีที่แล้ว'},
{name:'กานดา', loc:'บางแค', action:'แอดไลน์ขอประเมินราคา', time:'8 นาทีที่แล้ว'},
{name:'นภาพร', loc:'สาทร', action:'จองคิวสัปดาห์นี้', time:'12 นาทีที่แล้ว'},
{name:'ธีรวัฒน์',loc:'ดินแดง',action:'เพิ่งจองแพ็ค Premium', time:'15 นาทีที่แล้ว'},
{name:'ปริยา', loc:'จตุจักร', action:'จองซ้ำเป็นครั้งที่ 3', time:'18 นาทีที่แล้ว'},
];
let spIdx = 0, spDismissed = false, spTimer;
const spPopup = document.getElementById('sp-popup');
function showSP() {
if (spDismissed) return;
const p = proofs[spIdx % proofs.length];
document.getElementById('sp-msg').innerHTML = `<strong>${p.name} จาก ${p.loc}</strong><br>${p.action}`;
document.getElementById('sp-time').textContent = p.time;
spPopup.classList.add('show');
setTimeout(() => { if (!spDismissed) spPopup.classList.remove('show'); }, 5000);
spIdx++;
}
function spDismiss() {
spDismissed = true;
spPopup.classList.remove('show');
clearInterval(spTimer);
}
setTimeout(() => {
showSP();
spTimer = setInterval(showSP, 20000);
}, 8000);
const dateInput = document.getElementById('f-date');
if (dateInput) {
const d = new Date();
d.setDate(d.getDate() + 1);
dateInput.min = d.toISOString().split('T')[0];
}